<script setup lang="ts">
import { onMounted, reactive } from 'vue'; import { useRouter } from 'vue-router'; import StatusTag from '../components/common/StatusTag.vue'; import EmptyState from '../components/common/EmptyState.vue'; import { useCourses } from '../hooks/useCourses'; import type { Course } from '../types/course';
const router = useRouter(); const filters = reactive({ keyword: '', semester: '', status: '' }); const { courses, loading, fetchCourses } = useCourses();
onMounted(() => fetchCourses()); function search(){ fetchCourses(Object.fromEntries(Object.entries(filters).filter(([,v]) => v))); } function openCourse(row: Course) { router.push('/courses/' + row.id); }
</script><template><section class="page"><header><div><h2>课程管理</h2><p>按角色查看课程、处理开课、选课和状态流转。</p></div><el-button type="primary" v-permission="['ADMIN','TEACHER']">新建课程</el-button></header><el-form class="filters" inline><el-input v-model="filters.keyword" placeholder="课程名或编号" clearable /><el-input v-model="filters.semester" placeholder="学期" clearable /><el-select v-model="filters.status" placeholder="状态" clearable><el-option label="已发布" value="PUBLISHED"/><el-option label="进行中" value="IN_PROGRESS"/></el-select><el-button @click="search">筛选</el-button></el-form><el-table v-loading="loading" :data="courses" row-key="id" @row-click="openCourse"><el-table-column prop="code" label="编号" width="130"/><el-table-column prop="name" label="课程"/><el-table-column prop="teacher_name" label="教师"/><el-table-column prop="semester" label="学期"/><el-table-column label="状态"><template #default="{row}"><StatusTag :status="row.status" type="course"/></template></el-table-column><el-table-column prop="enrolled_count" label="人数" width="90"/></el-table><EmptyState v-if="!loading && courses.length===0" message="暂无课程" /></section></template>
